{
  "learning_outcomes": [
    {
      "unit_name": "Physical World and Measurement",
      "chapter_name": "Units and Measurements",
      "topic": "Need for measurement, SI units, Significant figures, Dimensional analysis",
      "outcomes": [
        "Understand the need for measurement and systems of units.",
        "Distinguish between fundamental and derived SI units.",
        "Apply rules for significant figures and determine uncertainty in results.",
        "Perform dimensional analysis to verify physical equations."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Straight Line",
      "topic": "Frame of reference, Differentiation/Integration for motion, Graphs",
      "outcomes": [
        "Define frame of reference and describe motion using differentiation and integration.",
        "Distinguish between uniform and non-uniform motion.",
        "Calculate average speed, average velocity, and instantaneous velocity.",
        "Interpret position-time and velocity-time graphs for uniformly accelerated motion."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Plane",
      "topic": "Vectors, Projectile Motion, Uniform Circular Motion",
      "outcomes": [
        "Perform vector operations including addition, subtraction, and resolution.",
        "Analyze projectile motion and uniform circular motion kinematically.",
        "Apply scalar and vector products to physical problems."
      ]
    },
    {
      "unit_name": "Laws of Motion",
      "chapter_name": "Laws of Motion",
      "topic": "Newton's Laws, Momentum, Friction, Circular Dynamics",
      "outcomes": [
        "Explain Newton's three laws and the concept of inertia.",
        "Apply conservation of linear momentum to collision problems.",
        "Analyze equilibrium conditions for concurrent forces.",
        "Differentiate between static, kinetic, and rolling friction."
      ]
    },
    {
      "unit_name": "Work, Energy and Power",
      "chapter_name": "Work, Energy and Power",
      "topic": "Work-Energy Theorem, Potential Energy, Collisions",
      "outcomes": [
        "Calculate work done by constant and variable forces.",
        "Apply the Work-Energy theorem to solve motion problems.",
        "Distinguish between conservative and non-conservative forces.",
        "Analyze elastic and inelastic collisions."
      ]
    },
    {
      "unit_name": "Motion of System of Particles and Rigid Body",
      "chapter_name": "System of Particles and Rotational Motion",
      "topic": "Centre of Mass, Torque, Angular Momentum, Moment of Inertia",
      "outcomes": [
        "Determine the centre of mass for particle systems and rigid bodies.",
        "Apply conservation laws for linear momentum and angular momentum.",
        "Analyze rotational motion equations and equilibrium of rigid bodies.",
        "Calculate moment of inertia for simple geometrical objects."
      ]
    },
    {
      "unit_name": "Gravitation",
      "chapter_name": "Gravitation",
      "topic": "Kepler's Laws, Universal Gravitation, Orbital Motion",
      "outcomes": [
        "State and apply Kepler's laws of planetary motion.",
        "Apply the universal law of gravitation to calculate forces.",
        "Analyze variations in acceleration due to gravity with altitude and depth.",
        "Calculate orbital velocity and escape speed."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Solids",
      "topic": "Elasticity, Stress-Strain, Hooke's Law",
      "outcomes": [
        "Define stress and strain and explain the stress-strain relationship.",
        "Apply Hooke's law to calculate Young's modulus, bulk modulus, and shear modulus.",
        "Understand Poisson's ratio and elastic energy."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Fluids",
      "topic": "Fluid Pressure, Viscosity, Bernoulli's Theorem, Surface Tension",
      "outcomes": [
        "Apply Pascal's law and calculate pressure due to fluid columns.",
        "Explain viscosity, Stokes' law, and terminal velocity.",
        "Apply Bernoulli's theorem to practical situations like Torricelli's law."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Thermal Properties of Matter",
      "topic": "Heat, Temperature, Thermal Expansion, Heat Transfer",
      "outcomes": [
        "Distinguish between heat and temperature.",
        "Calculate specific heat capacity and latent heat during state changes.",
        "Explain modes of heat transfer: conduction, convection, and radiation."
      ]
    },
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Laws of Thermodynamics, Processes",
      "outcomes": [
        "Define temperature using the Zeroth law.",
        "Apply the First and Second laws of thermodynamics to various processes.",
        "Distinguish between isothermal, adiabatic, reversible, and irreversible processes."
      ]
    },
    {
      "unit_name": "Behaviour of Perfect Gases and Kinetic Theory of Gases",
      "chapter_name": "Kinetic Theory",
      "topic": "Equation of State, Molecular Speeds, Degrees of Freedom",
      "outcomes": [
        "Derive the equation of state for a perfect gas.",
        "Explain kinetic theory assumptions and the concept of pressure.",
        "Relate temperature to mean kinetic energy and rms speed."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Oscillations",
      "topic": "Periodic Motion, Simple Harmonic Motion (SHM)",
      "outcomes": [
        "Define periodic motion and SHM equations.",
        "Analyze energy in simple harmonic motion.",
        "Derive the time period of a simple pendulum."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Waves",
      "topic": "Wave Motion, Superposition, Standing Waves, Beats",
      "outcomes": [
        "Distinguish between transverse and longitudinal waves.",
        "Apply the principle of superposition to standing waves in strings and pipes.",
        "Explain the phenomenon of beats."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–1: Electric Charges and Fields",
      "topic": "Coulomb's Law, Superposition Principle, Gauss's Theorem",
      "outcomes": [
        "Apply Coulomb's law to calculate forces between point charges.",
        "Use the superposition principle for multiple charge systems.",
        "Apply Gauss's theorem to find electric fields of symmetric distributions."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–2: Electrostatic Potential and Capacitance",
      "topic": "Electric Potential, Equipotential Surfaces, Capacitors",
      "outcomes": [
        "Calculate electric potential due to point charges and dipoles.",
        "Explain the concept of equipotential surfaces.",
        "Analyze series and parallel combinations of capacitors."
      ]
    },
    {
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Chapter–3: Current Electricity",
      "topic": "Ohm's Law, Resistivity, Kirchhoff's Rules",
      "outcomes": [
        "Relate drift velocity to electric current.",
        "Apply Ohm's law and analyze V-I characteristics.",
        "Use Kirchhoff's rules to solve complex circuits."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–4: Moving Charges and Magnetism",
      "topic": "Biot-Savart Law, Ampere's Law, Force on Conductors",
      "outcomes": [
        "Apply Biot-Savart law to calculate magnetic fields.",
        "Use Ampere's law for symmetric current distributions.",
        "Calculate force and torque on moving charges and current loops."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–5: Magnetism and Matter",
      "topic": "Magnetic Properties, Dipoles, Electromagnets",
      "outcomes": [
        "Classify materials as para-, dia-, or ferro-magnetic.",
        "Analyze the behavior of magnetic dipoles in external fields."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–6: Electromagnetic Induction",
      "topic": "Faraday's Laws, Lenz's Law, Self/Mutual Induction",
      "outcomes": [
        "State Faraday's laws of electromagnetic induction.",
        "Apply Lenz's law to determine the direction of induced current."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–7: Alternating Current",
      "topic": "AC Circuits, Reactance, Resonance, Power Factor",
      "outcomes": [
        "Analyze LCR series circuits using phasors.",
        "Calculate resonance conditions and power factor in AC circuits."
      ]
    },
    {
      "unit_name": "Unit–V Electromagnetic Waves",
      "chapter_name": "Chapter–8: Electromagnetic Waves",
      "topic": "Displacement Current, EM Spectrum",
      "outcomes": [
        "Explain the concept of displacement current.",
        "Identify regions of the electromagnetic spectrum and their uses."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–9: Ray Optics and Optical Instruments",
      "topic": "Reflection, Refraction, Lenses, Mirrors, Optical Instruments",
      "outcomes": [
        "Apply mirror and lens formulas to image formation.",
        "Analyze total internal reflection and optical fibers.",
        "Calculate magnifying power of microscopes and telescopes."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–10: Wave Optics",
      "topic": "Huygen's Principle, Interference, Diffraction",
      "outcomes": [
        "Apply Huygen's principle to derive laws of reflection and refraction.",
        "Analyze Young's double slit experiment for interference patterns."
      ]
    },
    {
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Chapter–11: Dual Nature of Radiation and Matter",
      "topic": "Photoelectric Effect, de-Broglie Relation",
      "outcomes": [
        "Explain the photoelectric effect using Einstein's equation.",
        "Apply the de-Broglie relation to matter waves."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Chapter–12: Atoms",
      "topic": "Rutherford Model, Bohr Model, Hydrogen Spectrum",
      "outcomes": [
        "Describe the Rutherford alpha-particle scattering experiment.",
        "Apply Bohr's model to calculate radius and energy of orbits."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Chapter–13: Nuclei",
      "topic": "Nuclear Composition, Binding Energy, Fission/Fusion",
      "outcomes": [
        "Explain mass defect and binding energy per nucleon.",
        "Differentiate between nuclear fission and fusion processes."
      ]
    },
    {
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Chapter–14: Semiconductor Electronics: Materials, Devices and Simple Circuits",
      "topic": "Semiconductors, p-n Junction Diode, Rectifiers",
      "outcomes": [
        "Distinguish between intrinsic and extrinsic semiconductors.",
        "Analyze I-V characteristics of a p-n junction diode in forward and reverse bias."
      ]
    }
  ]
}
